    ('MSCH-C 220', 'GAME TECHNOLOGY', '8879', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'FF 312', 'Nathan Mishler', 17, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides a survey of current technologies for creating games. These tools are also appropriate for projects in virtual and augmented reality and interactive journalism. Students acquire competency in several game engines demonstrated by the creation of several digital game prototypes using recently released tools.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 221', 'WRITING FOR ELECTRONIC MEDIA', '6516', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SY 105', 'Susan Williams', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Style, form, and preparation of written matereials for electronic media.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-C 221', 'WRITING FOR ELECTRONIC MEDIA', '12447', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SY 105', 'Susan Williams', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Style, form, and preparation of written matereials for electronic media.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-C 223', 'INTRODUCTION TO FILMMAKING', '13307', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'TV 251', 'Bear Brown', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Provides a conceptual framework for writing, designing, and evaluating a variety of media products. Media program design is not a hands-on production course but does offer an overview of the production process. Topics include scriptwriting, production design, visualization, composition, editing styles, and others.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('MSCH-C 228', 'MULTI-CAMERA TV STUDIO PRODUCTION I', '6557', 'Class Status', 'M Monday 5:30 PM–6:20 PM', 'TV 245', 'Glenn Hicks', 7, 'Lecture', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'A hands-on course focusing on multi-camera television studio production. Introduces technical aspects of the video signal and builds skills in the proficient operation of the cameras, audio board, lighting console, video switcher, character generator, and other studio equipment. Labs focus on developing these and other skills and producing multi-camera TV productions.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 228', 'MULTI-CAMERA TV STUDIO PRODUCTION I', '6558', 'Class Status', 'M Monday 8:30 AM–11:00 AM', 'FF 116', 'Siarra Bazler', 6, 'Discussion', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'A hands-on course focusing on multi-camera television studio production. Introduces technical aspects of the video signal and builds skills in the proficient operation of the cameras, audio board, lighting console, video switcher, character generator, and other studio equipment. Labs focus on developing these and other skills and producing multi-camera TV productions.', ARRAY[]::TEXT[], NULL),
