    ('MSCH-C 228', 'MULTI-CAMERA TV STUDIO PRODUCTION I', '6561', 'Closed', 'Th Thursday 8:30 AM–11:00 AM', 'FF 116', 'Siarra Bazler', 0, 'Discussion', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'A hands-on course focusing on multi-camera television studio production. Introduces technical aspects of the video signal and builds skills in the proficient operation of the cameras, audio board, lighting console, video switcher, character generator, and other studio equipment. Labs focus on developing these and other skills and producing multi-camera TV productions.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 228', 'MULTI-CAMERA TV STUDIO PRODUCTION I', '12156', 'Closed', 'Tu Tuesday 2:15 PM–4:45 PM', 'FF 116', 'Glenn Hicks', 0, 'Discussion', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'A hands-on course focusing on multi-camera television studio production. Introduces technical aspects of the video signal and builds skills in the proficient operation of the cameras, audio board, lighting console, video switcher, character generator, and other studio equipment. Labs focus on developing these and other skills and producing multi-camera TV productions.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 229', 'INTRODUCTION TO SINGLE-CAMERA PRODUCTION', '9593', 'Class Status', 'M Monday 5:30 PM–6:20 PM', 'TV 251', 'James Krause', 2, 'Lecture', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Outlines the basic procedures, techniques, and theories for the production of a video. Main focal points and concentrations include cinematography, lighting, and editing of digital video using single-cam and dual system audio/video recording techniques. Uses DSLR and cinema camera technology and incorporates an HD workflow.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 229', 'INTRODUCTION TO SINGLE-CAMERA PRODUCTION', '9594', 'Class Status', 'Th Thursday 9:00 AM–11:30 AM', 'TV 127', 'Christopher Robinson', 1, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Outlines the basic procedures, techniques, and theories for the production of a video. Main focal points and concentrations include cinematography, lighting, and editing of digital video using single-cam and dual system audio/video recording techniques. Uses DSLR and cinema camera technology and incorporates an HD workflow.', ARRAY[]::TEXT[], NULL),
