    ('MSCH-C 231', 'CREATING AN ONLINE MEDIA PORTFOLIO', '10410', 'Closed', NULL, 'WB WEB', 'Andrew Koop', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces the conceptual and practical aspects of building professional online portfolios using popular content management systems, such as WordPress, to showcase media work. Covers various aspects of the design process, including plugins, site security, visual templates, website configuration, and databases.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 232', 'MEDIA, FASHION AND POLITICS', '11460', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 114', 'Lisa Lenoir', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'It is through media that fashion reflects culture, social movements, and trends. This course explores the relationship between media, fashion, and politics and applies media effects and visual communication theory to the examination of key moments where fashion and politics have merged.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 241', 'WATCHING FILM', '9432', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TV 245', 'Tim Bell', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introduction to the power, pleasure, politics, and possibilities of cinema. Opportunity to develop film literacy through a better understanding of how film is and has been constructed and experienced. Provides critical techniques for analyzing and appreciating the many forms film has taken.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MSCH-C 249', 'MEDIA TECHNOLOGIES AND CULTURE', '12336', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'LH 125', 'Richard Jermain', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Explores how our understandings and experiences of culture and everyday life are transformed as media technology re-design, re-shape, re-administer, and re-organize our daily routines, habitats, habits, identities, and modes of communication.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
