    ('MSCH-C 251', 'STORY LAB II', '36802', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 052', 'Jared Meisinger', 5, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Intensive, hands-on course focuses on journalistic techniques for storytelling in a digital environment. Topics include audio and visual collection and editing, broadcast-style writing and voicing, interviewing, newswriting, reporting and verification techniques, social media and story development, principles of data, ethics and law in newsgathering and strategic communications contexts.', ARRAY['Class uses IU eTexts'], NULL),
