    ('MSCH-C 255', 'INTRODUCTION TO MEDIA AUDIENCE MEASUREMENT', '30015', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 216', 'Niki Fritz', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides an introduction to many of the ways audience behavior is measured and analyzed by media industry professionals and scholars. Covers skill such as basic measurement and questionnaire design principles, reaction time/response latency, continuous response measurement, and peripheral biometrics (heart rate, skin conductance, eye tracking, etc.).', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 270', 'MEDIA SKILLS WORKSHOP', '14466', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:20 PM', 'FF 003', 'Kirsten Payton', 6, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Media skills workshops that cover topics including media software training, camera presence training, media production workflow training, and other forms of skill development in digital and traditional media environments, particularly for those needing to develop technical skills in media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 270', 'MEDIA SKILLS WORKSHOP', '12929', 'Closed', 'W Wednesday 9:30 AM–11:00 AM', 'FF 060', 'Chad Parkinson', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Media skills workshops that cover topics including media software training, camera presence training, media production workflow training, and other forms of skill development in digital and traditional media environments, particularly for those needing to develop technical skills in media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 270', 'MEDIA SKILLS WORKSHOP', '13005', 'Closed', 'MW Monday, Wednesday 4:10 PM–5:00 PM', 'WB WEB', 'Adam Carroll', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Media skills workshops that cover topics including media software training, camera presence training, media production workflow training, and other forms of skill development in digital and traditional media environments, particularly for those needing to develop technical skills in media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 270', 'MEDIA SKILLS WORKSHOP', '12623', 'Closed', NULL, 'WB WEB', 'Justin Harter', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Media skills workshops that cover topics including media software training, camera presence training, media production workflow training, and other forms of skill development in digital and traditional media environments, particularly for those needing to develop technical skills in media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 320', 'SOCIAL MEDIA TACTICS', '11359', 'Closed', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'WB WEB', 'Samantha Dewig', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the knowledge and critical thinking skills needed to better understand social media, how they are utilized across fields such as advertising, journalism, media management and public relations, and what tactical and strategic considerations are necessary to most effectively use social networking tools in commercial and non-profit communication.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 320', 'SOCIAL MEDIA TACTICS', '33908', 'Closed', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'WB WEB', 'Samantha Dewig', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides the knowledge and critical thinking skills needed to better understand social media, how they are utilized across fields such as advertising, journalism, media management and public relations, and what tactical and strategic considerations are necessary to most effectively use social networking tools in commercial and non-profit communication.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 345', 'CINEMATIC ARTS WORKSHOP 3', '14779', 'Class Status', 'F Friday 1:00 PM–2:15 PM', 'TV 180', 'Malia Bruker', 10, NULL, 'Lecture', '1', 'RADIO-TV', ARRAY[]::TEXT[], 'Workshop course for third year BFA Cinematic Arts students to develop unique perspective and build Thesis pitches. This course culminates with a required portfolio review.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '31073', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 214', 'Edward Castronova', 4, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '14687', 'Class Status', 'W Wednesday 7:00 PM–8:45 PM', 'WB WEB', 'Barry Snyder', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '14163', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 215', 'Abby Gardner', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '14664', 'Closed', 'W Wednesday 12:45 PM–2:00 PM', 'FF 212', 'Jay Kincaid', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '33466', 'Closed', 'Tu Tuesday 10:00 AM–12:25 PM', 'FF 062', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 350', 'MEDIA TOPICS', '33477', 'Closed', 'Tu Tuesday 2:15 PM–4:45 PM', 'FF 052', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines emerging items in media, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 360', 'MEDIA SCHOOL BOOTCAMP', '37043', 'Class Status', 'F Friday 1:00 PM–5:00 PM', 'FF 114 FF 114', 'Patricia Whitaker', 6, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Professionally-oriented media courses taught by media professionals. Topics include hands-on media training, media planning, media analysis and criticism, and media career preparation. Featured instructors include professionals from fields as diverse as television and film production, advertising, public relations, journalism, sports media, game design, and film criticism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 360', 'MEDIA SCHOOL BOOTCAMP', '37044', 'Class Status', 'F Friday 1:00 PM–5:00 PM', 'FF 114 FF 114', 'Patricia Whitaker', 1, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Professionally-oriented media courses taught by media professionals. Topics include hands-on media training, media planning, media analysis and criticism, and media career preparation. Featured instructors include professionals from fields as diverse as television and film production, advertising, public relations, journalism, sports media, game design, and film criticism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 360', 'MEDIA SCHOOL BOOTCAMP', '36749', 'Class Status', 'F Friday 1:00 PM–6:00 PM', 'FF 114', 'Barry Snyder', 12, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Professionally-oriented media courses taught by media professionals. Topics include hands-on media training, media planning, media analysis and criticism, and media career preparation. Featured instructors include professionals from fields as diverse as television and film production, advertising, public relations, journalism, sports media, game design, and film criticism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 365', 'LIVE FROM LA: PROS MAKE MOVIES', '33835', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 7:00 PM–9:30 PM', 'FF 215', 'Michael Uslan', 6, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Featuring a series of interactive guest lectures featuring filmmaking professionals, students gain an understanding of every aspect of the filmmaking process from conceptualization to multi-platform distribution.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 366', 'THE BUSINESS OF PRODUCING MOTION PICTURES', '33836', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 3:00 PM–5:30 PM', 'FF 215', 'Michael Uslan', 10, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores the organizational, business, promotional, and legal aspects of producing a commercial feature film for a major motion picture studio.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 560', 'MOTION PICTURE PRODUCTION', '13497', 'Class Status', 'TuTh Tuesday, Thursday 12:30 PM–2:00 PM', 'TV 157', 'Susanne Schwibs', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'This class is a hands-on introduction to the technical and aesthetic basics of making 16mm silent films. Students learn how to design, direct, light, shoot, and edit several short films working individually as well as in groups.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 592', 'MEDIA GENRES', '30429', 'Class Status', 'Th Thursday 3:15 PM–6:45 PM', 'LI 044C', 'William Lawrence', 9, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Analysis and critique of cinema and film according to form, content, or technique. Topic varies: analysis of typical genres, such as westerns, situation comedies, documentaries, etc. Problems of generic description or definition: themes, conventions, iconography peculiar to given genres.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 792', 'ADVANCED SEMINAR IN MEDIA THEORY', '30024', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'FF 212', 'Rachel Plotnick', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topic varies: advanced study in media history and theory; major movements and historical periods and their relationship to the intellectual and cultural climate of the time; studies of technology and modes of production; advanced work in genre/auteur studies; close reading of media theories; new developments in theory and criticism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-D 331', 'SOCIAL MEDIA CULTURES', '32549', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WB WEB', 'Richard Jermain', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Social media technologies are an integral part of social life. This course helps students develop a vocabulary for understanding social media critically and analytically. Content includes a history of social media technologies, examinations of how people construct identities and relationships on social media, and how misinformation affects online experiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-D 331', 'SOCIAL MEDIA CULTURES', '36537', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Richard Jermain', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Social media technologies are an integral part of social life. This course helps students develop a vocabulary for understanding social media critically and analytically. Content includes a history of social media technologies, examinations of how people construct identities and relationships on social media, and how misinformation affects online experiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-D 337', 'DIGITAL MEDIA', '11566', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 216', 'Lois Scheidt', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops frameworks for understanding new media technologies in social contexts. Compares computing, networked digital media, and social media to prior eras of technological change, focusing on interactions among technological, industrial, regulatory, social, and cultural forces.', ARRAY[]::TEXT[], NULL),
    ('MSCH-D 337', 'DIGITAL MEDIA', '31076', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 210', 'Rachel Plotnick', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops frameworks for understanding new media technologies in social contexts. Compares computing, networked digital media, and social media to prior eras of technological change, focusing on interactions among technological, industrial, regulatory, social, and cultural forces.', ARRAY[]::TEXT[], NULL),
    ('MSCH-F 326', 'AUTHORSHIP IN THE MEDIA', '29936', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 210', 'Akinwumi Adesokan', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topic varies: in-depth analysis of directors, producers, or creative individuals in the media, viewed as "authors."', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-F 377', 'CINEMAS OF THE BLACK DIASPORA', '14017', 'Class Status', 'Tu Tuesday 2:20 PM–5:30 PM', 'FF 304C', 'Michael Martin', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines filmmaking in the black diaspora as a formally innovative visual and narrative art form in world cinema. Studies select films for their political and cultural significance and shared themes. Topics include colonialism and postcoloniality; race, gender and sexuality; migration and exile; modernity; and the dislocating processes of globalization.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('MSCH-F 381', 'HOLLYWOOD II: 1945 TO THE PRESENT', '12362', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'TV 226 CN B100', 'Ryan Powell', 1, NULL, 'Lecture', '3', 'RADIO-TV, IU CINEMA', ARRAY[]::TEXT[], 'Presents a critical survey of Hollywood cinema, from 1945 to the present, from the dual perspective of film history and cultural history. Focuses on stardom and performance, popular representations of race, class, gender and sexuality, technological change, genre theory, marketing and promotion, and the globalization of Hollywood.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-F 392', 'MEDIA GENRES', '33460', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TV 226 LI 048', 'Ryan Powell', 2, NULL, 'Lecture', '3', 'RADIO-TV, WELLS LIBRARY', ARRAY[]::TEXT[], 'Topic varies. Analysis of typical genres, such as westerns, situation comedies, documentaries, etc. Problems of generic description or definition: themes, conventions, iconography peculiar to given genres.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('MSCH-F 392', 'MEDIA GENRES', '12353', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 214', 'Tim Bell', 0, NULL, 'Lecture', '3', 'RADIO-TV, WELLS LIBRARY', ARRAY[]::TEXT[], 'Topic varies. Analysis of typical genres, such as westerns, situation comedies, documentaries, etc. Problems of generic description or definition: themes, conventions, iconography peculiar to given genres.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('MSCH-F 392', 'MEDIA GENRES', '34677', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'TV 180', 'Malia Bruker', 0, NULL, 'Lecture', '3', 'RADIO-TV, WELLS LIBRARY', ARRAY[]::TEXT[], 'Topic varies. Analysis of typical genres, such as westerns, situation comedies, documentaries, etc. Problems of generic description or definition: themes, conventions, iconography peculiar to given genres.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('MSCH-F 395', 'HORROR CINEMA', '32011', 'Class Status', 'Th Thursday 2:20 PM–5:30 PM', 'FF 304C', 'Michael Martin', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines horror in cinema as a cultural and cinematic form, and attempts to draw some conclusions about its "politics"-sexual, ethnic, familial, economic etc. Focuses on social changes in sexual mores. gender roles, family structure, political and economic events, and the increasing role of technology in our lives.', ARRAY[]::TEXT[], NULL),
    ('MSCH-F 398', 'NATIONAL AND TRANSNATIONAL CINEMAS', '33796', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 0011', 'Craig Cravens', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Historical survey of major national cinemas. Subject varies. Topics include Brazilian cinema, British cinema, Chinese cinema, French National cinema, German film culture, Indian cinema, and Italian cinema.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MSCH-F 420', 'TOPICS IN MEDIA HISTORY', '10142', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 304C', 'Tim Bell', 5, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Media historiography, topics in national media history, national and international movements and trends. Topic varies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-G 300', 'GAME PRODUCTION I', '3038', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 073', 'Nathan Mishler', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Students learn how to make digital game prototypes gaining hands-on experience while working in teams and using game engines such as Unity and Unreal. Student develop sound teamwork practices such as appropriate and timely communication, version control, and leadership; employ production methods such as agile and waterfall; and develop essential playtesting methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 300', 'GAME PRODUCTION I', '7527', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 073', 'Nathan Mishler', 5, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Students learn how to make digital game prototypes gaining hands-on experience while working in teams and using game engines such as Unity and Unreal. Student develop sound teamwork practices such as appropriate and timely communication, version control, and leadership; employ production methods such as agile and waterfall; and develop essential playtesting methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 310', 'GAME DESIGN I', '8453', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 310', 'Edward Castronova', 14, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines the structural and formal elements of games. Explores the theory of game design through deconstruction of tabletop games. Students will create, present, and analyze games in numerous contexts.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 320', 'GAME ART AND SOUND', '3035', 'Class Status', 'M Monday 11:10 AM–12:25 PM', 'FF 310', 'Gaby Benninghoff, Norbert Herber', 15, 'Lecture', 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This course combines a practical hands-on introduction to interactive media design with presentation and storytelling concepts. A wide range of design technologies including html, JavaScript, and cascading style sheets will be considered.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 320', 'GAME ART AND SOUND', '3036', 'Class Status', 'Tu Tuesday 9:30 AM–12:30 PM', 'FF 073', 'Norbert Herber', 3, 'Discussion', 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This course combines a practical hands-on introduction to interactive media design with presentation and storytelling concepts. A wide range of design technologies including html, JavaScript, and cascading style sheets will be considered.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 320', 'GAME ART AND SOUND', '3037', 'Class Status', 'Th Thursday 9:30 AM–12:30 PM', 'FF 073', 'Gaby Benninghoff', 12, 'Discussion', 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This course combines a practical hands-on introduction to interactive media design with presentation and storytelling concepts. A wide range of design technologies including html, JavaScript, and cascading style sheets will be considered.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 340', 'ANIMATION FOR DIGITAL MEDIA', '32275', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 073', 'Caleb Best', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Covers rigging, 3D animation, 2D animation, motion capture, and best practices for animating for specific platforms like film, games, and commercial uses.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 400', 'GAME PRODUCTION II', '7070', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 310', 'William Emigh', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Student development teams learn advanced techniques for conceiving and producing games. Course uses state-of-the-art game engines and industry production methods such as agile and waterfall with practice in overcoming obstacles such as bugs, poor communication, absent leadership. Prototypes will be tested and analyzed in statistical form.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 410', 'GAME DESIGN II: SYSTEMS', '6684', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 310', 'Patricia Pizer', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This course will develop the student''s ability to design game systems. Readings will be taken from systems design theory, social sciences, and engineering. Students will create systems in different software packages.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 424', 'CONCEPT ART FOR DIGITAL MEDIA', '32177', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'WB WEB', 'Autumn Almeida', 1, NULL, 'Laboratory', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Covers techiques for creating effective concept art for games and other digital media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 460', 'GAME WORKSHOP II: DEVELOPMENT', '10523', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 073', 'William Emigh', 0, NULL, 'Studio', '4', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Teams formed in MSCH-G 450 continue to work on their projects, focusing on the rapid iterative production cycles, working toward a fixed deadline. Impacts on players and culture assessed through testing and critique. Students will be required to submit their prototype to outside competition, such as a juried independent games festival.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 466', 'ADVANCED NARRATIVE DESIGN', '33794', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'WB WEB', 'Elizabeth Ballou', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Builds upon the interactive storytelling tools developed within MSCH-G 366, focusing upon the skills required to become a valuable member of a writing team. The course will culminate with the writing of a complete, self-contained game to be uploaded to itch.io.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 475', 'GAME STUDIO', '32264', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 073', 'Patricia Pizer, Gaby Benninghoff', 9, NULL, 'Studio', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores niche, independent, and avant-garde issues in game development under the direction of a faculty supervisor. Examples could include: Creature Design, Combat Animation, Interactive Audio, and Graphics Programming. This course culminates with a required portfolio review.', ARRAY[]::TEXT[], NULL),
    ('MSCH-G 901', 'ADVANCED RESEARCH', '7084', 'Class Status', NULL, NULL, 'Jason Peifer', 14, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have completed 90 credits hours that will count toward the PhD.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 110', 'ERNIE PYLE SCHOLAR HONORS FRESHMAN SEMINAR', '6582', 'Class Status', 'W Wednesday 6:30 PM–7:45 PM', 'FF 312', 'Stephen Layton', 5, NULL, 'Seminar', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical seminar for first-year Ernie Pyle Scholars that connects them with their faculty mentor. Explores critical issues in the U.S. media environment and introduces important ideas in the fields of journalism and strategic communication. Focuses on critical thinking, evaluating evidence, and how to strengthen media content.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 111', 'MEDIA HONORS FRESHMAN SEMINAR', '12630', 'Class Status', 'M Monday 6:30 PM–7:45 PM', 'FF 312', 'William Schwab', 3, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical seminar for first-year Media Scholars that connects them with their faculty mentor. Explores critical issues in the U.S. media environment and introduces important ideas in the fields of advertising, cinema studies, production, and sports media. Focuses on critical thinking, evaluating evidence, and how to strengthen media content.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 300', 'HONORS MEDIA LAW IN THE DIGITAL AGE', '13767', 'Class Status', 'W Wednesday 8:20 AM–10:50 AM', 'FF 312', 'Olivia Clavio', 21, NULL, 'Seminar', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'History and philosophy of laws pertaining to media, including free press, free speech, right of privacy, copyright, government regulation, and business law affecting media operations. Stresses responsibilities and freedoms in a democratic media system.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('MSCH-H 310', 'HONORS MEDIA TOPICS', '12397', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 312', 'James Shanahan', 12, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Covers a variety of topics from various media disciplines, including advertising, game design, journalism, law and public policy, media criticism, media production, and public relations. Develops advanced understanding of media topics and how media systems connect with culture, politics, and society. Evaluates and critically analyzes the underlying assumptions of media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 399', 'READING FOR HONORS', '1351', 'Class Status', NULL, NULL, 'Bonnie Layton', 16, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Honors readings course directed by an approved member of the Media School faculty. This course may be used as Honors credit for students within any of the Media School honors programs.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 497', 'SENIOR HONORS THESIS', '9731', 'Class Status', NULL, NULL, 'Bonnie Layton', 9, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Original research project, culminating in honors thesis to be written under direction of faculty.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 498', 'INDEPENDENT STUDY FOR HONORS', '11023', 'Class Status', NULL, NULL, 'Minjeong Kang', 5, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Opportunity for Media Honors students to engage in independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-H 498', 'INDEPENDENT STUDY FOR HONORS', '14802', 'Class Status', NULL, NULL, 'James Shanahan', 5, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Opportunity for Media Honors students to engage in independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 300', 'COMMUNICATIONS LAW', '14103', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'TV 245', 'Anthony Fargo', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Explores history and philosophy of laws pertaining to free press and free speech. Covers censorship, libel, contempt, obscenity, right of privacy, copyright, government regulations, and laws affecting the Internet and social media. Stresses responsibilities and freedoms in a democratic communications systems.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('MSCH-J 301', 'STORY LAB III', '12193', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 058', 'Joseph Coleman', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Intended for journalists, content creators, and content managers as they further develop their skills in story conception and design, fluency in verbal and written flair, and information gathering. Provides a bridge from Story Lab II to mastery-level courses in journalism and media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 301', 'STORY LAB III', '12868', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 060', 'Elaine Monaghan', 9, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Intended for journalists, content creators, and content managers as they further develop their skills in story conception and design, fluency in verbal and written flair, and information gathering. Provides a bridge from Story Lab II to mastery-level courses in journalism and media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 326', 'FASHION, BEAUTY, AND LIFESTYLE MEDIA', '11357', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'TV 251', 'Lesa Major', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Examines the world of media related to fashion, beauty, and lifestyle (FBL). Focuses on cultural influence, media history, sustainability, and the future of FBL. Includes analysis of bodies of knowledge associated with past and present expressions of human behaviors, beliefs, and experiences related to FBL.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 331', 'PODCASTING AND AUDIO STORYTELLING', '10456', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 058', 'Chad Carrothers', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores podcasting and audio storytelling as mediums of expression and content, through both listening and production. Provides practice in technical skills for audio storytelling and the application of those skills to the processes of finding stories, interviewing guests, and writing scripts.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 331', 'PODCASTING AND AUDIO STORYTELLING', '32258', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'FF 058', 'Chad Carrothers', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores podcasting and audio storytelling as mediums of expression and content, through both listening and production. Provides practice in technical skills for audio storytelling and the application of those skills to the processes of finding stories, interviewing guests, and writing scripts.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 343', 'BROADCAST NEWS', '6512', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 052', 'Anne Ryder', 7, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Basic television newsgathering skills, including generation of strong visual story ideas, shooting and editing with digital equipment and application of broadcast news ethics. Practice in telling stories effectively using video, natural sound, interviews and words. Emphasizes enterprise reporting, interviewing techniques and writing for broadcast.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-J 344', 'PHOTOJOURNALISM REPORTING', '13584', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 058', 'Ryan Comfort', 9, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Intermediate photojournalism course focused on advanced camera operation, visual storytelling, and photo editing in a digital media environment. Produce, edit, publish, and critique assignments: portraits, news, features, sports, and multimedia photo essays. Readings and discussions address ethics, law, history, and professional practice.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 353', 'ADVANCED BROADCAST NEWS', '6514', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 060', 'Anne Ryder', 12, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Advanced, accelerated emphasis on enterprising and executing broadcast stories of local and regional relevance. Report, shoot and edit news packages for use in weekly news broadcasts. News judgment, fairness, accuracy and technical skills are emphasized. Introduction to news producing and to creating social media relative to broadcast news.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '10472', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 214', 'Neal Moore', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '31090', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'FF 216', 'Samantha Stutsman', 4, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
