    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '14755', 'Class Status', 'W Wednesday 7:00 PM–8:45 PM', 'WB WEB', 'Barry Snyder', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
