    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '14166', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 215', 'Abby Gardner', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '14760', 'Closed', 'W Wednesday 12:45 PM–2:00 PM', 'FF 212', 'Jay Kincaid', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '30459', 'Closed', 'Tu Tuesday 10:00 AM–12:25 PM', 'FF 062', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '30462', 'Closed', 'Tu Tuesday 2:15 PM–4:45 PM', 'FF 052', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 360', 'JOURNALISM SPECIALTIES', '31482', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 114', 'Lesa Major', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course dealing with changing subjects and material from term to term.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 363', 'WEB AND MOBILE DESIGN', '12598', 'Class Status', NULL, 'WB WEB', 'Ross Hughes', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to the design, creation, and maintenance of websites and mobile platforms. Provides a strong foundation in the technical and design skills necessary to produce pleasant web experiences and to adapt to a constantly-changing medium. Covers design standards and their application in the design of messages using multiple media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 365', 'GRAPHIC DESIGN I', '9107', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 003', 'Cheryl Paul', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Instruction in page design, illustration and web design informed by design theory emphasizing critical thinking, creative problem solving, and ethical practice. Uses Adobe programs, HTML, CSS, and other coding to produce original media projects for mass and targeted audiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 365', 'GRAPHIC DESIGN I', '10546', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 062', 'Stephen Layton', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Instruction in page design, illustration and web design informed by design theory emphasizing critical thinking, creative problem solving, and ethical practice. Uses Adobe programs, HTML, CSS, and other coding to produce original media projects for mass and targeted audiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 365', 'GRAPHIC DESIGN I', '10547', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'FF 060', 'Cheryl Paul', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Instruction in page design, illustration and web design informed by design theory emphasizing critical thinking, creative problem solving, and ethical practice. Uses Adobe programs, HTML, CSS, and other coding to produce original media projects for mass and targeted audiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 365', 'GRAPHIC DESIGN I', '12337', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 003', 'Bonnie Layton', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Instruction in page design, illustration and web design informed by design theory emphasizing critical thinking, creative problem solving, and ethical practice. Uses Adobe programs, HTML, CSS, and other coding to produce original media projects for mass and targeted audiences.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 370', 'IU NEWSNET DAILY', '15038', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 214', 'Neal Moore', 8, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides hands-on TV newsroom experience by contributing to a daily newscast that is written, produced, and reported by IU students: the IU NewsNet Daily. Skills related to anchoring, reporting, and reporting are explored while contributing to a short-form live-streamed newscast in collaboration with other student news team members.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 385', 'TELEVISION NEWS REPORTING AND PRODUCING', '6517', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:15 PM', 'FF 060', 'Anne Ryder', 7, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Advanced writing, reporting and editing techniques. Producing television news stories and programs in field and studio environments with emphasis on conventional and innovative broadcast story forms. Practice in presentation skills and social media as applied to broadcast news stories with local and regional significance. Students produce a weekly news broadcast.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 403', 'LABORATORY/FIELD EXPERIENCE', '3276', 'Class Status', NULL, NULL, 'Teresa White', 4, NULL, 'Laboratory', '1', NULL, ARRAY[]::TEXT[], 'Laboratory or field experiences for prospective journalism teachers at the middle school or high school level.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 408', 'INVESTIGATIVE REPORTING', '11361', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 215', 'Kathleen Johnston', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines the heritage, tools and techniques of investigative reporting. Part seminar and part practicum, includes critical contemplation of philosophical, ethical, and legal issues; intensive work with public records; an introduction to data journalism; and practical experience producing a collaborative investigative project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 409', 'MEDIA MANAGEMENT', '6515', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'FF 114', 'Bob Zaltsberg', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Research seminar that examines techniques and processes used in managing media organizations. Through discussions, case analysis, and group projects, the course explores organizational missions and social responsibilities, market analysis techniques, personnel management issues, and budgeting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 410', 'THE MEDIA AS ETHICAL AND SOCIAL INSTITUTIONS', '10296', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 114', 'Joseph Coleman', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines functions and influences of news and public relations professionals in a networked society with primary focus on the United States. Analyzes professional and ethical values of journalists and public relations practicioners working in a digital, participatory media environment. Critical analysis of the relationship of media institutions and society, and the effects of political, economic, and cultural factors on media professionalism.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-J 410', 'THE MEDIA AS ETHICAL AND SOCIAL INSTITUTIONS', '13243', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 114', 'Elaine Monaghan', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines functions and influences of news and public relations professionals in a networked society with primary focus on the United States. Analyzes professional and ethical values of journalists and public relations practicioners working in a digital, participatory media environment. Critical analysis of the relationship of media institutions and society, and the effects of political, economic, and cultural factors on media professionalism.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-J 410', 'THE MEDIA AS ETHICAL AND SOCIAL INSTITUTIONS', '14790', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 210', 'Teresa White', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines functions and influences of news and public relations professionals in a networked society with primary focus on the United States. Analyzes professional and ethical values of journalists and public relations practicioners working in a digital, participatory media environment. Critical analysis of the relationship of media institutions and society, and the effects of political, economic, and cultural factors on media professionalism.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-J 414', 'NARRATIVE JOURNALISM', '34006', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 210', 'Thomas French', 0, NULL, 'Laboratory', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Advanced journalism course focused on the conceptualization, creation, and execution of multiple major stories. Fosters development of professional reporting approaches to enterprise stories and profiles and requires adherence to strict deadlines while effectively developing story ideas, avoiding errors, and creating work ready for professional publication.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 415', 'LITERARY JOURNALISM', '30019', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 058', 'Jeff LaFave', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'A study of literary forms and techniques used in journalism. Topics to be considered include formal considerations such as voice and structure, reporting methods and ethical issues. Students will supplement reading with writing experimental pieces of their own.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 423', 'PUBLIC OPINION', '12354', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 216', 'Mike Gruszczynski', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Behavioral study of nature, operation, molding, and influence of public opinion, with practice in its measurement and evaluation. Discussion of major political, social, economic, and cultural problems.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 431', 'ADVANCED PODCASTING AND AUDIO STORYTELLING', '29967', 'Class Status', 'W Wednesday 3:55 PM–6:55 PM', 'FF 214', 'Alex Chambers', 12, NULL, 'Laboratory', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Imparts an understanding of how audio production and editing work in a professional setting. Hones the technical skills required for production. Focuses on improving work quality, developing the speed and efficiency required in professional settings, and learning the critical listening skills needed to edit individually and in collaboration.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 453', 'METHODS OF TEACHING JOURNALISM', '5168', 'Class Status', NULL, NULL, 'Teresa White', 4, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Future journalism teachers examine methods, techniques, content, and materials applicable to teaching journalism and designing courses at the middle school or high school level.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 465', 'GRAPHIC DESIGN II', '10156', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 062', 'Stephen Layton', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Continues from Graphic Design I, incorporating advanced digital graphic design skills and creative problem solving for a series of media projects using illustration, logo design, creative typography and layout in a variety of media formats including print and interactive design for mobile devices.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 493', 'JOURNALISM: OFF CAMPUS REGISTRATION', '2041', 'Class Status', NULL, NULL, 'Galen Clavio', 25, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'This non-credit course is for journalism students studying off campus temporarily as part of the Bachelor of Arts in Journalism degree program.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 496', 'FOREIGN STUDY IN JOURNALISM', '6520', 'Class Status', NULL, NULL, 'Galen Clavio', 15, NULL, 'Independent Study', '3–8', NULL, ARRAY[]::TEXT[], 'Planning of research project during year preceding summer abroad. Time spent in research abroad must amount to at least one week for each credit hour granted. Research paper must be presented by end of semester following foreign study.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 510', 'MEDIA AND SOCIETY SEMINAR', '13660', 'Class Status', 'Tu Tuesday 12:45 PM–3:15 PM', 'FF 017', 'Elaine Monaghan', 3, NULL, 'Seminar', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Probing examination of structure and functions of mass media, stressing interaction among communication agencies and other social institutions. Critical analysis of media performance and policies in light of current economic, political, social, and intellectual thought. Comparative case studies of U.S. media with other national press systems.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 528', 'PUBLIC RELATIONS MANAGEMENT', '14621', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 210', 'Dave Groobert', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Designed to enable students to manage a public relations department. Theories and principles relevant to public relations practiced in agency, corporate and not-for-profit organizations will be covered. This will include developing goals and objectives, working with clients, developing budgets, and research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 529', 'PUBLIC RELATIONS CAMPAIGNS', '14679', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 062', 'Dave Groobert', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Designed to provide students with the opportunity to develop and execute a PR campaign for a local not-for-profit organization. Students will be exposed to relevant PR theory and in-depth case study analysis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 560', 'TOPICS COLLOQUIUM', '9419', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:55 PM', 'TV 250', 'James Krause', 3, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Topical seminar dealing with changing subjects and material from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 560', 'TOPICS COLLOQUIUM', '13505', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:25 PM', 'TV 180', 'Susanne Schwibs', 2, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Topical seminar dealing with changing subjects and material from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 572', 'MEDIA LAW IN THE DIGITAL AGE', '12960', 'Class Status', 'M Monday 9:00 AM–11:30 AM', 'FF 017', 'Anthony Fargo', 2, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'An examination of the theory and practice behind the development of free speech and free press law globally, with an emphasis on U.S. law. Research and discussion on developing law of privacy, access, and other constitutional problems.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-J 575', 'ARNOLT CENTER PRACTICUM', '14874', 'Class Status', NULL, 'HD TBA', 'Kathleen Johnston', 6, NULL, 'Practicum', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Students work alongside professional media members online and in the field, learning the latest techniques in investigative journalism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 577', 'INVESTIGATIVE REPORTING', '14623', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 215', 'Kathleen Johnston', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores practical skills of the investigative journalist both by studying professional investigative work and completing individual work using tools such as public records and computer-assisted reporting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 592', 'MEDIA INTERNSHIP', '3749', 'Class Status', NULL, NULL, 'Staff', 9, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Professional experience in media. Students hold work assignments with media organizations.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 700', 'SPECIALIZED REPORTING PROJECT', '6729', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA reporting project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '6726', 'Class Status', NULL, NULL, 'John Velez', 9, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '7655', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '9306', 'Class Status', NULL, NULL, 'Stephanie DeBoer', 9, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '9884', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '9885', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '9948', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '11877', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '11889', 'Class Status', NULL, NULL, 'Mike Gruszczynski', 9, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '35506', 'Class Status', NULL, NULL, 'Galen Clavio', 9, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-J 804', 'INDEPENDENT STUDY IN JOURNALISM', '36750', 'Closed', 'Intersession', NULL, 'Julien Mailland', 0, NULL, 'Independent Study', '1–9', NULL, ARRAY[]::TEXT[], 'Independent research and analysis for final MA thesis project.', ARRAY[]::TEXT[], NULL),
    ('MSCH-L 317', 'MEDIA ETHICS AND PROFESSIONAL RESPONSIBILITY', '3936', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 216', 'Julien Mailland', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'An analysis of the media environment including organizational structure, corporate responsibility, and the role of the individual in the media environment. Formulation of ethical principles to guide media policy and practice.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-L 322', 'MEDIA POLICYMAKING', '9509', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'TV 186', 'Matt Pierce', 13, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Overview of basic U.S. law and government. Specific analysis of who makes U.S. media policy, how it is done, and its effects. Course includes a case study of recent policymaking that varies each semester.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-M 310', 'DISRUPTORS: INTERNET INDUSTRIES', '11459', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'FF 212', 'Julien Mailland', 4, NULL, 'Seminar', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'What is the cultural mindset of technology entrepreneurs? How and why did the rise of Silicon Valley occur? This course considers the economic, social, financial, and legal forces present in the disruption industry, and how entrepreneurs leverage digital technologies and change the rules of how societies think and interact.', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 500', 'EPISTEMOLOGIES OF MEDIA', '10801', 'Class Status', 'W Wednesday 9:00 AM–11:30 AM', 'FF 017', 'Nicholas Browning', 3, NULL, 'Seminar', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This Media School core course provides graduate students with a selection of key concepts that have and continue to shape the study of media across multiple disciplines and fields of study. These key concepts are offered as a primer as students begin their program of study.', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 502', 'MEDIA RESEARCH', '33838', 'Class Status', 'Tu Tuesday 3:55 PM–6:25 PM', 'FF 212', 'Walter Gantz', 6, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Introduction to quantitative and qualitative research methodologies used in media.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-M 503', 'MEDIA THEORIES - SOCIAL SCIENCE PERSPECTIVE', '30292', 'Closed', 'Tu Tuesday 9:00 AM–11:30 AM', 'FF 212', 'Suzannah Comfort', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Introduces students to the wide range of social scientific theories which guide research in media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 504', 'MEDIA THEORIES - CRITICAL AND CULTURAL STUDIES', '12958', 'Class Status', 'Th Thursday 9:00 AM–11:30 AM', 'FF 212', 'Stephanie DeBoer', 7, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Introduces students to significant theoretical approaches to and debates concerning media across a range of competing and converging humanistic critical-cultural perspectives.', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 600', 'MEDIA ARTS & SCI COLLOQUIUM', '3040', 'Class Status', 'F Friday 1:30 PM–2:45 PM', 'FF 310', 'Jason Peifer', 20, NULL, 'Colloquium', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Introduction to current media research through the work of school members and visiting scholars.', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 699', 'MASTER''S CAPSTONE', '8111', 'Class Status', NULL, NULL, 'Jason Peifer', 8, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research under the direction of a member of the graduate faculty leading to a master''s capstone (thesis, creative project, comprehensive exam).', ARRAY[]::TEXT[], NULL),
    ('MSCH-M 899', 'PHD DISSERTATION RESEARCH', '6861', 'Class Status', NULL, NULL, 'Jason Peifer', 10, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research under the direction of a member of the graduate faculty leading to a PhD dissertation.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 331', 'INTRODUCTION TO SCREENWRITING', '12355', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TV 180', 'Clarisse Gamblin', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory course covering formal elements of Hollywood-style narrative screenwriting, focusing on screenplay format, stages of story development, story structure, character arcs, plotting, conflict, theme, point-of-view, dialogue, subtext, and scene description. Analyzes distinctions between literary writing and screenwriting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 331', 'INTRODUCTION TO SCREENWRITING', '12739', 'Class Status', 'W Wednesday 6:00 PM–8:30 PM', 'TV 180', 'Russell McGee', 2, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory course covering formal elements of Hollywood-style narrative screenwriting, focusing on screenplay format, stages of story development, story structure, character arcs, plotting, conflict, theme, point-of-view, dialogue, subtext, and scene description. Analyzes distinctions between literary writing and screenwriting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 331', 'INTRODUCTION TO SCREENWRITING', '13948', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'TV 226', 'Clarisse Gamblin', 2, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory course covering formal elements of Hollywood-style narrative screenwriting, focusing on screenplay format, stages of story development, story structure, character arcs, plotting, conflict, theme, point-of-view, dialogue, subtext, and scene description. Analyzes distinctions between literary writing and screenwriting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 331', 'INTRODUCTION TO SCREENWRITING', '12624', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'TV 226', 'Carly Short', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory course covering formal elements of Hollywood-style narrative screenwriting, focusing on screenplay format, stages of story development, story structure, character arcs, plotting, conflict, theme, point-of-view, dialogue, subtext, and scene description. Analyzes distinctions between literary writing and screenwriting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 331', 'INTRODUCTION TO SCREENWRITING', '14913', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 216', 'Paul Shoulberg', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory course covering formal elements of Hollywood-style narrative screenwriting, focusing on screenplay format, stages of story development, story structure, character arcs, plotting, conflict, theme, point-of-view, dialogue, subtext, and scene description. Analyzes distinctions between literary writing and screenwriting.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 335', 'PRODUCTION AS CRITICISM', '12338', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FF 216 LI 048', 'Stephanie DeBoer', 2, NULL, 'Lecture', '3', 'FRANKLIN HALL, WELLS LIBRARY', ARRAY[]::TEXT[], 'By modeling the techniques of historically significant films, provides both conceptual and hands-on experience for researching, writing, and producing different genres of cinematic media. Emphasizes conceptual processes from script to the completed film.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('MSCH-P 344', 'INTRODUCTION TO DOCUMENTARY FILMMAKING: THEORY & PRACTICE', '34142', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'TV 245', 'Saddam Al-Zubaidi', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Explores the variety of documentary film practice. Examines fundamental issues, styles, and techniques (realism, voice, ethics, observation, interview, re-enactment, etc.) through hands-on exercises, screenings, discussions, lectures, and the production of a short form documentary', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 344', 'INTRODUCTION TO DOCUMENTARY FILMMAKING: THEORY & PRACTICE', '34676', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'TV 180', 'Malia Bruker', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Explores the variety of documentary film practice. Examines fundamental issues, styles, and techniques (realism, voice, ethics, observation, interview, re-enactment, etc.) through hands-on exercises, screenings, discussions, lectures, and the production of a short form documentary', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 352', 'EDITING FOR CINEMA', '9418', 'Class Status', 'Tu Tuesday 11:10 AM–12:25 PM', 'TV 245', 'Kevin Weaver', 1, 'Lecture', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Analyze and assemble dramatic scenes under a variety of conditions and narrative strategies. Examine editing theories, techniques and procedures, issues of continuity, effects, movement and sound as they relate to the fundamentals of cinematic montage and visual storytelling. Explore a variety of topics and experiences designed to broaden understanding of the art of cinematic storytelling and montage.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 352', 'EDITING FOR CINEMA', '11445', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'TV 250', 'Andrew Behringer', 1, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Analyze and assemble dramatic scenes under a variety of conditions and narrative strategies. Examine editing theories, techniques and procedures, issues of continuity, effects, movement and sound as they relate to the fundamentals of cinematic montage and visual storytelling. Explore a variety of topics and experiences designed to broaden understanding of the art of cinematic storytelling and montage.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 352', 'EDITING FOR CINEMA', '11482', 'Closed', 'W Wednesday 3:55 PM–5:10 PM', 'TV 250', 'Andrew Behringer', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Analyze and assemble dramatic scenes under a variety of conditions and narrative strategies. Examine editing theories, techniques and procedures, issues of continuity, effects, movement and sound as they relate to the fundamentals of cinematic montage and visual storytelling. Explore a variety of topics and experiences designed to broaden understanding of the art of cinematic storytelling and montage.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 352', 'EDITING FOR CINEMA', '12617', 'Closed', 'Th Thursday 3:55 PM–5:10 PM', 'TV 250', 'Andrew Behringer', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Analyze and assemble dramatic scenes under a variety of conditions and narrative strategies. Examine editing theories, techniques and procedures, issues of continuity, effects, movement and sound as they relate to the fundamentals of cinematic montage and visual storytelling. Explore a variety of topics and experiences designed to broaden understanding of the art of cinematic storytelling and montage.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 352', 'EDITING FOR CINEMA', '33605', 'Closed', 'W Wednesday 11:10 AM–12:25 PM', 'TV 250', 'Andrew Behringer', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Analyze and assemble dramatic scenes under a variety of conditions and narrative strategies. Examine editing theories, techniques and procedures, issues of continuity, effects, movement and sound as they relate to the fundamentals of cinematic montage and visual storytelling. Explore a variety of topics and experiences designed to broaden understanding of the art of cinematic storytelling and montage.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 353', 'PRODUCTION AUDIO', '9599', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'TV 250', 'Norbert Herber', 0, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Practice a broad range of audio recording and mixing exercises in preparation for advanced courses in film, video, and documentary production. Hands-on activities introduce the most commonly encountered types of audio equipment and their proper use.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 353', 'PRODUCTION AUDIO', '14764', 'Closed', 'M Monday 6:30 PM–9:00 PM', 'TV 250', 'Manny Knowles', 0, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Practice a broad range of audio recording and mixing exercises in preparation for advanced courses in film, video, and documentary production. Hands-on activities introduce the most commonly encountered types of audio equipment and their proper use.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 354', 'PROGRAM GRAPHICS AND ANIMATION', '8892', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:55 PM', 'TV 250', 'James Krause', 0, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Covers technical skills and creative principles required to produce graphics and animation for television and digital filmmaking applications. Reinforces skills acquisition through hands-on activites and projects using industry-standard software.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 356', 'MULTI-CAMERA TV STUDIO PRODUCTION II', '9080', 'Class Status', 'Th Thursday 11:45 AM–3:15 PM', 'FF 116', 'Nate Wrigley', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Advanced, hands-on course in TV studio production. Builds on existing proficiency within the TV studio environment through directing shows, developing content, and operating gear in a multi-camera TV studio. Provides instruction and practice in high-level communication skills required to produce multi-camera studio projects.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 360', 'MOTION PICTURE PRODUCTION', '13496', 'Class Status', 'TuTh Tuesday, Thursday 12:30 PM–2:00 PM', 'TV 157', 'Susanne Schwibs', 2, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'A hands-on introduction to the technical and aesthetic basics of making 16mm silent films, including the skills needed to design, direct, light, shoot, and edit this type of production', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-P 361', 'INTERMEDIATE MOTION PICTURE PRODUCTION', '10301', 'Closed', 'M Monday 9:35 AM–10:50 AM', 'TV 245', 'Bear Brown', 0, 'Lecture', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the ecology of the department-based work environment of a professional motion picture set. Provides practice in the various film crew roles, including producer, director, cinematographer, gaffer, script supervisor, production designer, assistant director, sound recordist, boom operator, data wrangler/editor, grip, and unit production manager.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 361', 'INTERMEDIATE MOTION PICTURE PRODUCTION', '10302', 'Closed', 'M Monday 11:00 AM–3:00 PM', 'TV 127', 'Jeffery Garland', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the ecology of the department-based work environment of a professional motion picture set. Provides practice in the various film crew roles, including producer, director, cinematographer, gaffer, script supervisor, production designer, assistant director, sound recordist, boom operator, data wrangler/editor, grip, and unit production manager.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 361', 'INTERMEDIATE MOTION PICTURE PRODUCTION', '11483', 'Closed', 'F Friday 10:00 AM–2:00 PM', 'TV 127', 'Jeffery Garland', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the ecology of the department-based work environment of a professional motion picture set. Provides practice in the various film crew roles, including producer, director, cinematographer, gaffer, script supervisor, production designer, assistant director, sound recordist, boom operator, data wrangler/editor, grip, and unit production manager.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 361', 'INTERMEDIATE MOTION PICTURE PRODUCTION', '14767', 'Closed', 'Tu Tuesday 5:45 PM–9:45 PM', 'TV 127', 'Steven Braunlin', 0, 'Laboratory', 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the ecology of the department-based work environment of a professional motion picture set. Provides practice in the various film crew roles, including producer, director, cinematographer, gaffer, script supervisor, production designer, assistant director, sound recordist, boom operator, data wrangler/editor, grip, and unit production manager.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 362', 'CINEMATOGRAPHY', '9420', 'Class Status', 'Th Thursday 11:45 AM–2:45 PM', 'TV 127', 'Jeffery Garland', 2, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on camera to post workflows and professional camera crew skills, including how to operate cinema package cameras and light for cinematic productions. Explores and evaluates cinema techniques that are utilized in film and television production.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 362', 'CINEMATOGRAPHY', '13442', 'Class Status', 'Tu Tuesday 11:45 AM–2:45 PM', 'TV 127', 'Jeffery Garland', 3, NULL, 'Laboratory', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on camera to post workflows and professional camera crew skills, including how to operate cinema package cameras and light for cinematic productions. Explores and evaluates cinema techniques that are utilized in film and television production.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 369', 'SOUND DESIGN', '3666', 'Closed', 'MW Monday, Wednesday 8:50 AM–10:50 AM', 'TV 250', 'Norbert Herber', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introduces sound design for film and television with a focus on the role of the Sound Effects Editor. Explores the ways sound is used to enhance visual language, provide narrative cues, create a sense of space and place, focus audience attention, provide compositional structure, and create psychological ambience.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 422', 'COLOR CORRECTION & FINISHING', '9421', 'Class Status', 'Tu Tuesday 4:45 PM–8:15 PM', 'TV 157L', 'Scott Carmichael', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the techniques, tools, and skills required to prepare an edited program for final distribution, including color-correction, stylization, video scopes, and dialogue normalization.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 423', 'ADVANCED CINEMATIC LIGHTING', '14798', 'Class Status', 'W Wednesday 11:45 AM–2:45 PM', 'TV 127', 'Bear Brown', 3, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Expands on basic cinematic lighting techniques and establishes a correlation between lighting for film and digital mediums through analytical and hands-on applications of lighting and film/electronic cinematography.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 431', 'FEATURE FILM SCREENWRITING', '11558', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 310', 'Paul Shoulberg', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Builds on the foundations of MSCH-P 331, by focusing on the creation of original, feature-length Hollywood style narrative screenplays. Workshops delve deeper into genre conventions, story structure, character development, plotting, conflict, theme, point of view, dialogue, and sub text.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 432', 'TV SERIES WRITING', '13477', 'Closed', 'M Monday 6:00 PM–8:30 PM', 'TV 180', 'Russell McGee', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Builds on the foundations of MSCH-P 331, by focusing on the development process and writing of a long form narrative series, including the creation of a series bible, an outline for the first season, and a written and revised pilot episode for an original series.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 452', 'TOPICS IN DESIGN AND PRODUCTION', '14757', 'Class Status', 'W Wednesday 7:00 PM–8:45 PM', 'WB WEB', 'Barry Snyder', 3, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Exploration of design or production problems and issues in telecommunications. Topics vary.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 452', 'TOPICS IN DESIGN AND PRODUCTION', '13471', 'Closed', 'MW Monday, Wednesday 9:30 AM–10:45 AM', 'FF 214', 'Austin Francalancia', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Exploration of design or production problems and issues in telecommunications. Topics vary.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 452', 'TOPICS IN DESIGN AND PRODUCTION', '14762', 'Closed', 'W Wednesday 12:45 PM–2:00 PM', 'FF 212', 'Jay Kincaid', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Exploration of design or production problems and issues in telecommunications. Topics vary.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 461', 'BFA CINEMA THESIS: PRODUCTION', '11715', 'Class Status', NULL, NULL, 'Bear Brown', 2, NULL, 'Laboratory', '3', NULL, ARRAY[]::TEXT[], 'First semester of two-semester BFA Thesis sequence. Begins with the vetting of scripts and project proposals, along with consultation on pre-production efforts, then moves into thesis film production, including all production documentation/reports, proper workflow organization, and preparation for postproduction.', ARRAY[]::TEXT[], NULL),
    ('MSCH-P 468', 'DOUBLE EXPOSURE: ADVANCED COLLABORATIVE WORKSHOP', '10299', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:25 PM', 'TV 180', 'Susanne Schwibs', 1, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Film and music students collaborate in the production of a short film to be screened, with live musical accompaniment, at the IU Cinema. Covers all stages of production, with special emphasis on collaboration between music and sound teams, as well as preparation of a media artifact for public exhibition.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 348', 'PUBLIC RELATIONS PLANNING AND RESEARCH', '11815', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 215', 'Esi Thompson Tani-Eshon', 4, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Theories and principles relevant to public relations research and strategic planning, including development of goals and objectives, client relationships, budgets, and research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 348', 'PUBLIC RELATIONS PLANNING AND RESEARCH', '11814', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 214', 'Minjeong Kang', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Theories and principles relevant to public relations research and strategic planning, including development of goals and objectives, client relationships, budgets, and research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 348', 'PUBLIC RELATIONS PLANNING AND RESEARCH', '14013', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 212', 'Esi Thompson Tani-Eshon', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Theories and principles relevant to public relations research and strategic planning, including development of goals and objectives, client relationships, budgets, and research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 349', 'PUBLIC RELATIONS WRITING', '7783', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 003', 'Erica Sagon', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops the professional writing skills expected of beginning public relations practitioners, including different approaches to a variety of audiences and media. Focuses on the basics of good writing as well as the art of writing. Provides practice in AP style. Imparts skills needed to work effectively with real-world clients.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 349', 'PUBLIC RELATIONS WRITING', '11844', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 003', 'Matt Guschwan', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops the professional writing skills expected of beginning public relations practitioners, including different approaches to a variety of audiences and media. Focuses on the basics of good writing as well as the art of writing. Provides practice in AP style. Imparts skills needed to work effectively with real-world clients.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 349', 'PUBLIC RELATIONS WRITING', '14830', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 060', 'Tori Lawhorn', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops the professional writing skills expected of beginning public relations practitioners, including different approaches to a variety of audiences and media. Focuses on the basics of good writing as well as the art of writing. Provides practice in AP style. Imparts skills needed to work effectively with real-world clients.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 360', 'PUBLIC RELATIONS TOPICS', '14827', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FF 214', 'Neal Moore', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course that focuses on emerging items in public relations and strategic communication, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
