    ('MSCH-R 360', 'PUBLIC RELATIONS TOPICS', '14824', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 216', 'Carolyn Hadlock', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course that focuses on emerging items in public relations and strategic communication, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 360', 'PUBLIC RELATIONS TOPICS', '31483', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 114', 'Lesa Major', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course that focuses on emerging items in public relations and strategic communication, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 360', 'PUBLIC RELATIONS TOPICS', '31485', 'Closed', 'Tu Tuesday 10:00 AM–12:25 PM', 'FF 062', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course that focuses on emerging items in public relations and strategic communication, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 360', 'PUBLIC RELATIONS TOPICS', '31488', 'Closed', 'Tu Tuesday 2:15 PM–4:45 PM', 'FF 052', 'Patricia Whitaker', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Topical course that focuses on emerging items in public relations and strategic communication, including related social and political issues, content creation and production, and unique trends and events.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 429', 'PUBLIC RELATIONS CAMPAIGNS', '11801', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 062', 'Dave Groobert', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Covers development and execution of a public relations campaign for a non-profit organization as well as public relations theory and in-depth care study analysis. Provides training and practice in developing and pitching a proposal to meet a client''s business objectives. Includes media relations and crisis communications training.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 429', 'PUBLIC RELATIONS CAMPAIGNS', '11800', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 062', 'Dave Groobert', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Covers development and execution of a public relations campaign for a non-profit organization as well as public relations theory and in-depth care study analysis. Provides training and practice in developing and pitching a proposal to meet a client''s business objectives. Includes media relations and crisis communications training.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 431', 'PUBL RELATIONS FOR NONPROFITS', '33707', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 058', 'Minjeong Kang', 11, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'This seminar focuses on how a non-profit organization creates images and how it shapes its programs and goals to gain public support. Assignments and readings are designed to foster a practical understanding of promotional techniques and campaigns using journalistic and other media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 450', 'PUBLIC RELATIONS MANAGEMENT', '14352', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 210', 'Dave Groobert', 2, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Focuses on the strategic, financial, and leadership skills necessary to become a manager and leader in the public relations industry. Examines the functions of public relations management, and application of these functions in a variety of industry roles and job settings.', ARRAY[]::TEXT[], NULL),
    ('MSCH-R 501', 'PRINCIPLES OF STRATEGIC COMMUNICATION', '12959', 'Class Status', 'W Wednesday 8:20 AM–10:50 AM', 'FF 212', 'Melanie Sarge', 13, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Introduces students to various theories, principles, and practices of strategic communication across marketing, advertising, and public relations contexts, highlighting nuanced differences. Also focuses on the unifying elements of ethical persuasion, advocacy, and activism.', ARRAY[]::TEXT[], NULL),
    ('MSCH-S 310', 'SEX IN THE MEDIA', '5245', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'FF 312', 'Niki Fritz', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores the role and portrayal of sex and sexuality in media and examines in detail the potential social and psychological effects of exposure to sexual content in the media.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 312', 'POLITICS AND THE MEDIA', '4234', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'AC C102', 'Julia Fox', 10, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Examines the relationship between media and modern politics. Topics will vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 317', 'CHILDREN AND MEDIA', '12331', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 114', 'Nicole Martins', 7, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Acquaints students with the popular and research literatures on children and media, including television and computers. Students will be expected to identify recurring themes and topics related to children and media and to evaluate their significance in understanding the role of media in children''s lives.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 348', 'AUDIENCE ANALYSIS', '10230', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 312', 'Paul Wright', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'The behavior, descriptors, and measurement of telecommunications audiences. Sample survey, focus groups, and other research methods used by the telecommunications industry.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 348', 'AUDIENCE ANALYSIS', '33994', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 312', 'Ted Jamison-Koenig', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'The behavior, descriptors, and measurement of telecommunications audiences. Sample survey, focus groups, and other research methods used by the telecommunications industry.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 348', 'AUDIENCE ANALYSIS', '36825', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 062', 'Niki Fritz', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'The behavior, descriptors, and measurement of telecommunications audiences. Sample survey, focus groups, and other research methods used by the telecommunications industry.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-S 452', 'COMMUNICATING CLIMATE CHANGE', '30021', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FF 210', 'Ryan Comfort', 1, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides an overview of public opinion on climate change, introduces different theoretical perspectives on the barriers to public engagement with the topic, and examines the effectiveness of different methods of climate change communication designed to foster public engagement.', ARRAY['COLL (CASE) Sustainability Literacy credit'], NULL),
    ('MSCH-T 311', 'HISTORY OF ELECTRONIC MEDIA', '9555', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'TV 186', 'Matt Pierce', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Discussion of how today''s electronic media was shaped by past inventions, business innovations and regulatory decisions. Traces the development of mass communication from the telegraph to the telephone, radio, and television to the arrival of digital communication technologies.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-T 311', 'HISTORY OF ELECTRONIC MEDIA', '15169', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'AC C102', 'Julia Fox', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Discussion of how today''s electronic media was shaped by past inventions, business innovations and regulatory decisions. Traces the development of mass communication from the telegraph to the telephone, radio, and television to the arrival of digital communication technologies.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-T 427', 'INTERNATIONAL MEDIA NETWORKS', '3433', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'FF 215', 'Harmeet Sawhney', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'A comparative study of the development of broadband networks in different parts of the world. The interaction between national telecommunications policies and international arrangements, institutions, and structures.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-T 522', 'MANAGING THE CREATIVE PROCESS', '9480', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'TV 157', 'Ray Nowosielski', 7, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Examination of the business side of video production with emphasis on the role of the producer and/or production manager, including production team organization, schedules, budgets, contracts, markets and intellectual property.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 540', 'SPECIAL PROJECTS IN MEDIA', '3039', 'Class Status', NULL, NULL, 'Jason Peifer', 8, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Individual readings or production projects in telecommunications.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 540', 'SPECIAL PROJECTS IN MEDIA', '9308', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Individual readings or production projects in telecommunications.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 540', 'SPECIAL PROJECTS IN MEDIA', '9313', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Individual readings or production projects in telecommunications.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 540', 'SPECIAL PROJECTS IN MEDIA', '14966', 'Class Status', NULL, NULL, 'Staff', 5, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Individual readings or production projects in telecommunications.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 540', 'SPECIAL PROJECTS IN MEDIA', '35779', 'Closed', NULL, NULL, 'Susanne Schwibs', 0, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Individual readings or production projects in telecommunications.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 576', 'MEDIA PRODUCTION PRACTICUM', '13073', 'Class Status', 'Tu Tuesday 2:20 PM–4:50 PM', 'TV 157', 'James Krause', 5, NULL, 'Practicum', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Production training involving watching/listening to media, analysis and discussion of production techniques, and the creation of original media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 577', 'NEW MEDIA DESIGN', '34835', 'Class Status', NULL, NULL, 'Anne Ryder', 9, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Training in conceptualization and design of new media, including actual production at the prototype level. In addition, completion of a paper that applies design theories to the project work undertaken in the class.', ARRAY[]::TEXT[], NULL),
    ('MSCH-T 583', 'INTRODUCTION TO DOCUMENTARY PRACTICE', '10300', 'Class Status', 'W Wednesday 2:20 PM–4:50 PM', 'TV 157', 'Susanne Schwibs', 8, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Graduate students review and refine basic production skills in preparation for teaching positions. Basic media production concepts, techniques, and hands-on training. Prior understanding of the production process is expected.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 360', 'THE MEDIA SCHOOL IN LOS ANGELES', '15001', 'Class Status', 'Th Thursday 7:00 PM–10:00 PM', 'HD TBA', 'Barry Snyder', 15, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on topics relevant to the Media School''s Semester in Los Angeles program. Explores various aspects of the entertainment and media industries under the instruction of industry professionals.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 360', 'THE MEDIA SCHOOL IN LOS ANGELES', '15002', 'Class Status', 'Tu Tuesday 7:00 PM–10:00 PM', 'HD TBA', 'Barry Snyder', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on topics relevant to the Media School''s Semester in Los Angeles program. Explores various aspects of the entertainment and media industries under the instruction of industry professionals.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 360', 'THE MEDIA SCHOOL IN LOS ANGELES', '15003', 'Class Status', 'W Wednesday 7:00 PM–10:00 PM', 'HD TBA', 'Ward Roberts', 14, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on topics relevant to the Media School''s Semester in Los Angeles program. Explores various aspects of the entertainment and media industries under the instruction of industry professionals.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 360', 'THE MEDIA SCHOOL IN LOS ANGELES', '15004', 'Class Status', 'M Monday 7:00 PM–10:00 PM', 'HD TBA', 'Edward Timpe', 16, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on topics relevant to the Media School''s Semester in Los Angeles program. Explores various aspects of the entertainment and media industries under the instruction of industry professionals.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 373', 'MEDIA INTERNSHIP IN LOS ANGELES', '15157', 'Class Status', NULL, NULL, 'Galen Clavio, Isabel Madejski', 21, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Faculty-supervised work in a media field related to student''s academic interests. Credits based on at least 45 work hours per credit hour with a maximum of 6 credit hours applied toward any MSCH degree or concentration. Student must write a critical analysis paper and be evaluated by a workplace supervisor.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 374', 'WIUX INTERNSHIP', '10539', 'Class Status', NULL, NULL, 'Galen Clavio', 3, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised internship working in a media-related role with WIUX Student Radio.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 375', 'IUSTV INTERNSHIP', '10543', 'Class Status', NULL, NULL, 'Galen Clavio', 4, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised internship working in a media-related role with IUSTV.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 376', 'IDS INTERNSHIP', '10544', 'Class Status', NULL, NULL, 'Galen Clavio', 7, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised internship working in a media-related role with the Indiana Daily Student.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 377', 'NSJC INTERNSHIP', '10545', 'Class Status', NULL, NULL, 'Galen Clavio', 8, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised internship working in a media-related role with the National Sports Journalism Center.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 386', 'INTRODUCTION TO LIVE EVENT SPORTS PRODUCTION', '13800', 'Class Status', NULL, NULL, 'Sarah Curtiss', 1, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'Provides students with an introductory experience to live event production in sports media. Students engage in training on live video production, including camera work, graphics, replay, audio, and technical directing. Students apply training through a series of live video productions of sporting events through the Big Ten Network Plus program.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 472', 'MEDIA INTERNSHIP', '14849', 'Class Status', 'Intersession', NULL, 'Galen Clavio, Tara Heckler, Jill Romack, Paul Wright', 32, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Faculty-supervised work in a media field related to student''s academic interests. Credits based on at least 45 work hours per credit hour with a maximum of 6 credit hours applied toward the B.A. in Media or the B.S. in Game Design. Student must write a critical analysis paper and be evaluated by a workplace supervisor.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 472', 'MEDIA INTERNSHIP', '1350', 'Closed', NULL, NULL, 'Galen Clavio, Tara Heckler, Paul Wright, Jill Romack', 0, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Faculty-supervised work in a media field related to student''s academic interests. Credits based on at least 45 work hours per credit hour with a maximum of 6 credit hours applied toward the B.A. in Media or the B.S. in Game Design. Student must write a critical analysis paper and be evaluated by a workplace supervisor.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 476', 'WTIU PRODUCTION WORKSHOP', '4398', 'Class Status', NULL, NULL, 'Galen Clavio', 10, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'With close supervision by WTIU station or production management, student is responsible for pre-production planning, production coordination and execution, postproduction, critical and audience evaluation of programs for broadcast. Develop professional working relationships and portfolio.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 486', 'ADVANCED LIVE EVENT SPORTS PRODUCTION', '13801', 'Class Status', NULL, NULL, 'Kevon Wilson', 7, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'Provides students with prior training in live sports event production further practical education. Continued development through hands-on experience with live video production, including camera, graphics, replay, audio, technical directing, directing, and producing. Students provide production of sporting events through the Big Ten Network Plus program and Indiana University Radio-Television Services.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 488', 'MULTI CAMERA TV NEWS PRODUCTION PRACTICUM', '13806', 'Class Status', 'F Friday 12:00 PM–3:00 PM', 'TV 103A', 'Eric Bolstridge', 6, NULL, 'Practicum', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Hands-on course focusing on multi-camera television news production. Technical aspects of the video signal and skills in the proficient operation of the cameras, audio board, lighting console, video switcher, character generator, and other studio equipment. This practicum focuses on developing these and other skills and producing multi-camera News TV productions.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 489', 'ARNOLT CENTER PRACTICUM', '14781', 'Class Status', NULL, NULL, 'Galen Clavio, Kathleen Johnston, Barbara Truesdell', 3, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Offers hands-on experience in the Michael I. Arnolt Center for Investigative Journalism. Provides techniques needed to work as an investigative journalist in a multi-media world.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 490', 'PROJECTS IN MEDIA', '6669', 'Class Status', NULL, NULL, 'Galen Clavio', 2, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Opportunity for individual and group projects in media production and journalism; work with faculty member on individual or group basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 490', 'PROJECTS IN MEDIA', '9234', 'Class Status', NULL, NULL, 'William Emigh', 4, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Opportunity for individual and group projects in media production and journalism; work with faculty member on individual or group basis.', ARRAY[]::TEXT[], NULL),
