    ('MSCH-X 498', 'RESEARCH IN MEDIA', '6519', 'Class Status', NULL, NULL, 'Staff', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Opportunity for independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 498', 'RESEARCH IN MEDIA', '8282', 'Class Status', NULL, NULL, 'Staff', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Opportunity for independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 498', 'RESEARCH IN MEDIA', '9881', 'Class Status', NULL, NULL, 'Staff', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Opportunity for independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCH-X 498', 'RESEARCH IN MEDIA', '11890', 'Class Status', NULL, NULL, 'Staff', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Opportunity for independent readings, research, and experimentation on relevant issues in media and communications; work with faculty member on individual basis.', ARRAY[]::TEXT[], NULL),
    ('MSCI-G 901', 'ADVANCED RESEARCH', '3161', 'Class Status', NULL, NULL, 'Heather O''Hagan, Valerie O''Loughlin, Polly Husmann', 18, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 100', 'CURRENT TOPICS IN BIOMEDICAL SCIENCES', '5128', 'Closed', 'F Friday 1:55 PM–2:45 PM', 'AC C102', 'J.T. Cornelius', 0, NULL, 'Lecture', '1', 'CEDAR HALL', ARRAY[]::TEXT[], 'Exploration of a major issue in biomedical sciences, using analysis of scientific literature, and interpretation of contemporary research data. Readings and lectures are supplemented by whole-class and small-group discussion, and by frequent written assignments.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 100', 'CURRENT TOPICS IN BIOMEDICAL SCIENCES', '15012', 'Closed', 'Tu Tuesday 1:55 PM–2:45 PM', 'WI C111', 't''Jacques Guillot', 0, NULL, 'Lecture', '1', 'CEDAR HALL', ARRAY[]::TEXT[], 'Exploration of a major issue in biomedical sciences, using analysis of scientific literature, and interpretation of contemporary research data. Readings and lectures are supplemented by whole-class and small-group discussion, and by frequent written assignments.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 115', 'INTRODUCTION TO ANATOMY AND PHYSIOLOGY', '6676', 'Closed', NULL, 'WB WEB', 'Lauralyn Riggins', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This one semester lecture-based course examines the basics of human anatomy and physiology including anatomical terminology, basic biochemistry, cells, and tissues. The primary focus of the course is the study of organ systems including integumentary, skeletal, muscular, nervous, endocrine, cardiovascular, lymphatic/immune, respiratory, digestive, urinary, and reproductive systems. The course includes an introduction to common human disease processes.', ARRAY['IUB GenEd N&M credit - Natural Science
Class uses IU eTexts'], NULL),
    ('MSCI-M 131', 'DISEASE AND THE HUMAN BODY', '2200', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SE 105', 'Jim Davis, Pat Clark', 13, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('MSCI-M 216', 'MEDICAL SCIENCE OF PSYCHOACTIVE DRUGS', '2201', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 1050', 'Bruce Martin', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An entry-level examination of the biological mechanisms underlying the effects of psychoactive drugs. Drug actions in the brain, spinal cord, heart, lungs, liver, and other organs and tissues will be detailed. Molecular mechanisms and genetic factors involved in drug-induced therapeutic and adverse effects will be emphasized.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('MSCI-M 325', 'INTRODUCTION TO MEDICINE', '30295', 'Class Status', 'W Wednesday 5:30 PM–7:10 PM', 'AH C3062', 'John Foley, Robert Sung', 2, NULL, 'Lecture', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This is a broad overview of the education and training required to practice medicine, including information about applying to medical school. In addition, it introduces concepts from medical ethics, emotional intelligence, financial considerations, medical specialties and practice sites, orientating students towards developing competencies required for effective patient care.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 335', 'BIOPSYCHOSOCIAL MEDICINE- A CASE STUDY APPROACH', '8803', 'Closed', NULL, 'WB WEB', 'Lauralyn Riggins', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This hybrid course targets those students who are interested in exploring the emerging science of mind-body medicine. It is appropriate for students studying a range of professional careers having to do with health and well-being. It will emphasize the interconnection between biological, social, psychological and behavior sciences as they relate to health and disease. Some of the topics explored will include nature versus nurture, emotions on health, psychoneuroimmunology, epigenetics, neuroplasticity, neuroendocrine system, stress resilience versus disease, and the field of biopsychosocial medicine as compared to the long-standing biomedical model.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCI-M 401', 'BASIC AND CLINICAL PHARMACOLOGY', '10009', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Charles Rudick', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This 400 level course provides comprehensive study of clinical pharmacology that will prepare students for graduate studies in all medical health fields such as Medical, Nursing, and Physician Assistant school and many other health professions. Clinical Pharmacology will begin with how medications are processed by the body and what clinical effect they have on the body. The course will then focus on the medications used for disorders of the immune, nervous, hematological, cardiovascular, renal, respiratory, digestive, skeletal, dermatologic and reproductive systems. Students will learn the mechanisms of action, clinical indications, adverse effects and drug interactions of all medication in the course.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 410', 'RESEARCH METHODS IN CELL AND MOLECULAR BIOLOGY', '33067', 'Class Status', 'MW Monday, Wednesday 10:00 AM–12:00 PM', 'JH 102', 'Heather O''Hagan', 12, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The purpose of this course is to give students interested in pursuing bench research a strong fundamental understanding of proper experimental design and commonly used research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 410', 'RESEARCH METHODS IN CELL AND MOLECULAR BIOLOGY', '30589', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The purpose of this course is to give students interested in pursuing bench research a strong fundamental understanding of proper experimental design and commonly used research methods.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 450', 'UNDERGRADUATE RESEARCH IN BIOMEDICAL SCIENCES', '2202', 'Class Status', NULL, NULL, 'Claire Walczak', 18, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Research for undergraduate students. Introduction to research methods and scientific investigation in the biomedical sciences. A written report is required upon completion of the research.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 490', 'SPECIAL TOPICS IN BIOMEDICAL SCIENCES', '2203', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'Intensive study of a selected topic in biomedical sciences. Topics will vary.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 499', 'INTERNSHIP IN MEDICAL SCIENCES INSTRUCTION', '2204', 'Class Status', NULL, NULL, 'Ben Skutnik, Stacey Dunham, Valerie O''Loughlin, Danielle Hanson', 11, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Supervised teaching experience in undergraduate medical science courses.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 501', 'BASIC AND CLINICAL PHARMACOLOGY', '10010', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Charles Rudick', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides a comprehensive study of clinical pharmacology for graduate students in a variety of health fields. Students will learn the mechanisms of action, clinical indications, adverse effects and drug interactions of various medications used to treat disorders of major body systems, such as circulatory and nervous.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 507', 'LABORATORY ROTATIONS', '8147', 'Class Status', NULL, NULL, 'Heather O''Hagan', 5, NULL, 'Research', '1–4.5', NULL, ARRAY[]::TEXT[], 'Introduction to research in different faculty labs before choosing a thesis lab.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 510', 'RESEARCH METHODS IN CELL AND MOLECULAR BIOLOGY', '30294', 'Class Status', 'MW Monday, Wednesday 10:00 AM–12:00 PM', 'JH 102', 'Heather O''Hagan', 2, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The purpose of this course is to give incoming graduate students a strong fundamental understanding of proper experimental design and commonly used research methods. The course will be taught by critically evaluating common cellular and molecular biology techniques and by critiquing primary literature that utilizes these techniques.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 512', 'SPECIAL TOPICS IN CELL MOLECULAR AND CANCER BIOLOGY', '8501', 'Class Status', 'Th Thursday 3:00 PM–6:00 PM', 'SI 001', 'Adam Zlotnick, Roger Innes', 5, NULL, 'Seminar', '1–3', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Graduate course that discusses special topics in Cell Molecular and Cancer Biology.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 535', 'BIOPSYCHOSOCIAL MEDICINE AND HEALTH', '8804', 'Class Status', NULL, 'WB WEB', 'Lauralyn Riggins', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This hybrid course targets students interested in exploring the emerging science of mind-body medicine. It is appropriate for students studying a range of professional careers having to do with health and well-being and emphasizes the interconnection between biological, social, psychological and behavior sciences as they relate to health and disease.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCI-M 550', 'SEMINAR IN CANCER BIOLOGY', '7095', 'Class Status', 'Tu Tuesday 10:25 AM–11:15 AM', 'JH 102', 'Richard Carpenter', 15, NULL, 'Seminar', '1', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'A journal club and seminar series focused on molecular mechanisms in cancer biology. Students will present once per semester in the journal club and attend a cancer biology seminar series.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 553', 'SPECIAL TOPICS IN MEDICAL SCIENCES', '8935', 'Class Status', NULL, NULL, 'Staff', 8, NULL, 'Seminar', '1.5', NULL, ARRAY[]::TEXT[], 'A seminar course focused on new topics in Cell, Molecular, and Cancer Biology with a focus on Medicine. Each topic will be introduced by an expert in the field. Students will then critically review recent literature.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 584', 'MOLECULAR GENETICS', '11764', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 344', 'Brian Calvi, Peter Hollenhorst, Lachezar Nikolov', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introductory molecular genetics for graduate students. Will introduce genetic approaches in multiple model organisms and molecular concepts underpinning regulation of the genome and gene expression.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 630', 'MOLECULES TO CELLS TO TISSUES', '7621', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:40 PM–4:40 PM', 'AH C3061 AH C3061', 'Wayne Forrester', 10, NULL, 'Lecture', '7', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Course emphasizes foundational underpinning of concepts integral to the disciplines of biochemistry, cell and molecular biology, histology, and medical genetics - especially how they relate to the practice of medicine. Course consists of lecture, small group sessions, and labs.', ARRAY[]::TEXT[], NULL),
    ('MSCI-M 800', 'LABORATORY RESEARCH', '7535', 'Class Status', NULL, NULL, 'Heather O''Hagan', 30, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Independent laboratory research toward MS or PhD degree.', ARRAY[]::TEXT[], NULL),
