    ('MUS-A 115', 'ANALYSIS OF MUSIC CREATION AND PRODUCTION I', '30269', 'Class Status', 'MF Monday, Friday 10:25 AM–11:15 AM', 'SM C018', 'Andrew West, Michael Stucker', 4, 'Lecture', 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Students enrolled in this course will survey songwriting techniques for multiple genres and styles in popular music by analyzing existing songs. Through the analysis of lyrics, melody, chord progressions, and imagery, students will identify stylistic devices and specific approaches to be incorporated into their own compositions.', ARRAY[]::TEXT[], NULL),
