    ('MUS-E 130', 'INTRODUCTION TO MUSIC LEARNING', '34636', 'Class Status', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'SM 340', 'Peter Miksza, Xizi Zang', 13, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Introduction to the philosophy, sociology, and psychology of music. Survey of careers in music including teaching (school and private), performing, scholarship, publishing, and technical fields.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 131', 'FRESHMAN COLLOQUIUM IN MUSIC EDUCATION', '4422', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'MC 036 MC 040', 'Julia Shaw', 3, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Introduction to the development of instructional materials and professional artifacts through observations, peer teaching, and the application of technological resources.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 218', 'CULTURAL DIVERSITY IN MUSIC PEDAGOGY', '11203', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MA 007', 'Lissa May', 3, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'This course explores ways in which educators can respond pedagogically and ethically to human diversity present in music classrooms. We will explore several approaches to teaching, applying their central premises to school music contexts: world music pedagogy; culturally relevant, responsive, and sustaining pedagogy; and anti-racist pedagogy.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 232', 'INCLUSIVE PARTICIPATORY MUSIC PRACTICES', '6451', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SM 242', 'Amanda Draper', 5, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An examination of various avenues for learning music in contemporary culture. Includes an overview of informal music making practices such as garage bands and singing circles, learning and engagement with music from diverse places throughout the world, and using technology for creative music making. Contains a service learning component.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 303', 'VIOLIN/VIOLA PEDAGOGY I', '6619', 'Closed', 'W Wednesday 1:55 PM–2:45 PM', 'SM 350', 'Mimi Zweig', 0, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Learning the skills to teach beginning violin or viola students through lectures, observation of private and group lessons, and teaching children under the supervision of the instructor. Paper on a topic from the course.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 306', 'CELLO PEDAGOGY', '2272', 'Closed', 'W Wednesday 11:10 AM–12:15 PM', 'JS 225', 'Emilio Colon', 0, NULL, 'Lecture', '2', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'Comparisons of cello methods and materials, study of right-hand and left-hand techniques, observation of teaching, and practical experience teaching private and class lessons. Paper on a topic from the course.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 312', 'ARRANGING FOR INSTRUMENTAL AND VOCAL GROUPS', '2273', 'Class Status', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'MC 036', 'Brian Shaw', 6, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 342', 'METHODS AND MATERIALS FOR TEACHING ELEMENTARY MUSIC', '30591', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–11:05 AM', 'SM 005', 'Brent Gault', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Detailed study of current teaching techniques for the elementary school music class; Dalcroze, Kodaly, and Orff techniques; review of current textbooks and other materials; classroom recorder and guitar. A grade of C+ or higher is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 343', 'METHODS AND MATERIALS FOR TEACHING CHORAL MUSIC', '30593', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:40 PM', 'SM 340', 'Julia Shaw', 8, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Organization and development of choral groups; voice production; rehearsal techniques; tone, diction, and phrasing; materials suitable for school choruses at secondary level. A grade of C+ or higher is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 344', 'METHODS AND MATERIALS FOR TEACHING INSTRUMENTAL MUSIC', '30595', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:40 PM', 'SM 005', 'Brian Shaw', 15, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Teaching methods and materials; organization of the instrumental curriculum. A grade of C+ or higher is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 400', 'UNDERGRADUATE READINGS IN MUSIC EDUCATION', '4350', 'Class Status', NULL, NULL, 'Kyle Adams', 5, NULL, 'Seminar', '2–3', NULL, ARRAY[]::TEXT[], 'Examination of current topics relevant to the field of music education as found in the professional literature. Sample topics include teaching competencies, curricular content, choral and instrumental techniques, and innovative methodology.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 413', 'HARP PEDAGOGY', '6620', 'Class Status', NULL, NULL, 'Elzbieta Szmyt', 1, NULL, 'Lecture', '2', NULL, ARRAY[]::TEXT[], 'A survey of teaching materials and methods for the harp and texts on basic musicianship. Observation of private lessons and class instruction.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 414', 'APPLIED HARP PEDAGOGY', '9536', 'Class Status', NULL, NULL, 'Elzbieta Szmyt', 9, NULL, 'Lecture', '2', NULL, ARRAY[]::TEXT[], 'A supervised series of private and class harp lessons.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 434', 'ADMINISTRATION OF SCHOOL BANDS AND ORCHESTRAS', '30590', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'SM 153A', 'Jason Nam', 16, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Teaching, organization, and administration of school wind ensembles, percussion ensembles, and orchestras. A grade of C+ or higher is required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 459', 'INSTRUMENTAL PEDAGOGY', '5546', 'Class Status', 'F Friday 12:45 PM–2:10 PM', 'SM 267', 'Linda Strommen', 11, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 459', 'INSTRUMENTAL PEDAGOGY', '34480', 'Class Status', 'M Monday 4:20 PM–6:10 PM', 'SM 344', 'Otis Murphy', 4, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
