    ('MUS-E 480', 'METHODS AND MATERIALS FOR TEACHING STRING MUSIC', '33975', 'Class Status', 'M Monday 2:55 PM–3:55 PM', 'SM 356 SM 242', 'Frank Diaz', 9, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 489', 'ORGAN PEDAGOGY', '30284', 'Class Status', 'F Friday 12:45 PM–2:25 PM', 'MA 407', 'Janette Fishell', 3, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'An examination of pedagogical practices and methods relating to the instruction of organ students at all levels.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 493', 'PIANO PEDAGOGY', '2274', 'Closed', 'TuTh Tuesday, Thursday 1:55 PM–2:45 PM', 'SM C113', 'Vicki King', 0, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Methods and materials for teaching individuals and class on the intermediate and advanced levels.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 494', 'VOCAL PEDAGOGY', '2275', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'MA 007', 'Nate Paul, Brian Horne', 9, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Principles of voice production. Quality, diction, range, breathing, vocalization, dynamics, agility, and vocal hygiene as bases for an approach to vocal teaching.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 502', 'THE PRACTICE OF MUSIC TEACHING', '3232', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'SM 242', 'Amanda Draper', 7, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An overview of learning theories and curriculum design related to specific music education fields. Includes an investigation of general learning theories and application of these to choral general and instrumental music teaching situations. Field experience with opportunities for observation of area teachers and implementation of curriculum.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 503', 'VIOLIN/VIOLA PEDAGOGY I', '2276', 'Closed', 'W Wednesday 1:55 PM–2:45 PM', 'SM 350', 'Mimi Zweig', 0, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Learning the skills to teach beginning violin or viola students through lectures, observation of private and group lessons, and teaching children under the supervision of the instructor. Paper on a topic from the course.', ARRAY[]::TEXT[], NULL),
