    ('MUS-E 506', 'CELLO PEDAGOGY', '2277', 'Closed', 'W Wednesday 11:10 AM–12:15 PM', 'JS 225', 'Emilio Colon', 0, NULL, 'Lecture', '2', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'Comparisons of cello methods and materials, study of right hand and left hand techniques, observation of teaching, practical experience teaching private and class lessons. Paper on a topic from the course.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 508', 'EUPHONIUM PEDAGOGY', '9425', 'Class Status', NULL, NULL, 'Joey Tartell', 19, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'This course is designed to acquaint graduate euphonium students with current methods and materials in teaching and their practical applications. Students will receive an introduction to the latest pedagogical methods, music teaching technology, and apps that aid in teaching lessons.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 509', 'HORN PEDAGOGY', '10907', 'Class Status', NULL, NULL, 'Joey Tartell', 19, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'Observation of two private lessons per week taught by major teachers. Term paper required.', ARRAY[]::TEXT[], NULL),
