    ('MUS-E 522', 'MUSIC IN EARLY CHILDHOOD', '30505', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'SM 242', 'Brent Gault', 8, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'A survey of research literature in musical development and applications to the selection of materials and teaching methods for the preschool- and Kindergarten-aged child.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 524', 'EXPLORATORY TEACHING IN GENERAL MUSIC K-12', '8408', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–11:05 AM', 'SM 005', 'Brent Gault', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 527', 'ADVANCED INSTRUMENTAL METHODS', '14522', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:40 PM', 'SM 005', 'Brian Shaw', 15, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'The application of current teaching techniques to group instrumental instruction. Designed for students with previous teaching experience.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 528', 'ADVANCED CHORAL METHODS AND MATERIALS', '5383', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:40 PM', 'SM 340', 'Julia Shaw', 4, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'The application of current teaching techniques to a variety of choral ensemble types. Designed for students with previous teaching experience.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 530', 'LEARNING PROCESSES IN MUSIC', '30485', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SM 356', 'Peter Miksza', 3, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Description and prescriptive conditions of musical learning and development. Included are interdisciplinary studies of learning involving musical, psychological, physiologican, cultural, and sociological factors.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 533', 'RESEARCH IN MUSIC EDUCATION', '2279', 'Class Status', NULL, NULL, 'Peter Miksza', 10, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Techniques and procedures of research in music education, including problem definition, research design, sampling procedure, and treatment of data. Research report required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 545', 'GUIDED PROFESSIONAL EXPERIENCE', '2280', 'Class Status', NULL, NULL, 'Peter Miksza', 10, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Further development of professional skills in teaching, supervision, and administration by means of laboratory techniques and use of School of Music facilities and resources. Evidence of competency to carry on independent work required.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 559', 'INSTRUMENTAL PEDAGOGY', '5547', 'Class Status', 'F Friday 12:45 PM–2:10 PM', 'SM 267', 'Linda Strommen', 11, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Pedagogy classes pertaining to the individual instruments.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 559', 'INSTRUMENTAL PEDAGOGY', '34481', 'Class Status', 'M Monday 4:20 PM–6:10 PM', 'SM 344', 'Otis Murphy', 4, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Pedagogy classes pertaining to the individual instruments.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 580', 'METHODS AND MATERIALS FOR TEACHING STRING MUSIC', '33976', 'Class Status', 'M Monday 2:55 PM–3:55 PM', 'SM 356 SM 242', 'Frank Diaz', 9, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'String teaching materials, methods, and techniques for use with K-12 students. This course will cover the skills and knowledge that will enable students to successfully teach public school string classes from the beginning through the advanced levels. Knowledge of various pedagogical approaches as well as practical application of those concepts in this course.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 589', 'ORGAN PEDAGOGY', '30282', 'Class Status', 'F Friday 12:45 PM–2:25 PM', 'MA 407', 'Janette Fishell', 3, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'An examination of pedagogical practices and methods relating to the instruction of organ students at all levels.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 598', 'PRACTICUM/THESIS PROPOSAL IN MUSIC EDUCATION', '5248', 'Class Status', NULL, NULL, 'Peter Miksza', 20, NULL, 'Lecture', '0', NULL, ARRAY[]::TEXT[], 'Enrollment required prior to the final semester of coursework. Development of Practicum or Thesis methodology and analysis procedures.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 599', 'PRACTICUM IN MUSIC EDUCATION', '5169', 'Class Status', NULL, NULL, 'David Cartledge', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Research-based practical or creative project or investigation (may be a phase of a cooperative study or an independent project).', ARRAY[]::TEXT[], NULL),
    ('MUS-E 600', 'THESIS IN MUSIC EDUCATION', '2281', 'Class Status', NULL, NULL, 'David Cartledge', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Quantitative or qualitative scholarly research document.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 610', 'MASTER''S CAPSTONE IN MUSIC EDUCATION', '15334', 'Class Status', NULL, 'HD TBA', 'David Cartledge', 10, NULL, 'Lecture', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'One of the following: 1) research-based practical or creative project or investigation (may be a phase of a cooperative study or an independent project); 2) Quantitative or qualitative scholarly research document; 3) Portfolio assessed by oral examination. This course is eligible for deferred (R) grading.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 625', 'THE ADMIN OF MUS IN HIGHER ED', '9864', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SM 149C', 'Gwyn Richards', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 631', 'QUANTITATIVE RESEARCH IN MUSIC EDUCATION', '30490', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:50 PM', 'RA B109', 'Peter Miksza', 4, NULL, 'Research', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 650', 'MUSIC EDUCATION RESEARCH COLLOQUIUM', '6943', 'Class Status', 'F Friday 2:45 PM–4:00 PM', 'SM 350', 'Peter Miksza', 11, NULL, 'Lecture', '0', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Research presentations, poster presentations, and lectures by graduate students, faculty, and guest lecturers. Required of doctoral students in music education each semester of full-time enrollment.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 658', 'SEMINAR IN MUSIC EDUCATION', '7691', 'Class Status', 'Th Thursday 3:10 PM–5:10 PM', 'SM 263', 'Lauren Richerme', 6, NULL, 'Lecture', '2', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-E 661', 'HISTORICAL RESEARCH IN MUSIC EDUCATION', '30487', 'Class Status', 'Tu Tuesday 3:10 PM–4:40 PM', 'MA 004', 'Lissa May', 7, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'An examination of the methods used in historical research in music education with a survey of major studies and trends of inquiry.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 662', 'PUBLIC LECTURE IN MUSIC EDUCATION', '2282', 'Class Status', NULL, NULL, 'Peter Miksza', 14, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'A presentation made to the university community or at an appropriate professional conference. The paper presented must be approved by the student''s advisory committee.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 663', 'PUBLIC RESEARCH LECTURE IN MUSIC EDUCATION', '7599', 'Class Status', NULL, NULL, 'Peter Miksza', 13, NULL, 'Lecture', '0', NULL, ARRAY[]::TEXT[], 'A research presentation made to the university community and submitted for consideration to an appropriate professional conference. The paper presented must represent new, doctoral-level research, and be approved by a primary faculty supervisor and a second faculty reader.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 672', 'LARGE JAZZ ENSEMBLE PEDAGOGY AND LITERATURE', '30324', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'HD TBA', 'Brent Wallarab', 5, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course will give the student real-time experience observing and assisting university jazz ensemble instructors. Through assistance, observation, and discussion, the student will acquire a diverse set of skills enabling them to program, rehearse, conduct, and manage a large jazz ensemble of varying skill level.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 694', 'APPLIED VOICE PEDAGOGY', '30325', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'MA 006', 'Brian Horne', 7, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'A course intended to prepare doctoral students for positions in higher education. Class components will include preparation of such items as a curriculum vitae, philosophy of teaching, personal website, as well as a major research paper and multi-media lecture.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 695', 'VOICE PEDAGOGY: RESEARCH FOUNDATIONS', '6992', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SM 350', 'Brian Gill', 4, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'This class examines current knowledge of the singing voice based on research in anatomy, physiology, and acoustics with a focus on the study of voice science. Through readings as well as discussions and demonstrations in class, students learn theoretical concepts based in current scientific research regarding voice use.', ARRAY[]::TEXT[], NULL),
    ('MUS-E 700', 'DISSERTATION IN MUSIC EDUCATION', '2283', 'Class Status', NULL, NULL, 'David Cartledge', 30, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-F 200', 'MUSIC EDUCATION INSTRUMENTAL LABORATORY', '8105', 'Class Status', 'F Friday 12:45 PM–2:00 PM', 'MC 036 SM 005', 'Frank Diaz', 6, NULL, 'Lecture', '1', 'MUSICAL ARTS CENTER, SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Preparing lessons, teaching, and conducting heterogeneous instrumental ensembles.', ARRAY[]::TEXT[], NULL),
