    ('MUS-F 300', 'PIANO ACCOMPANYING', '3234', 'Class Status', 'W Wednesday 11:35 AM–12:25 PM', 'JS 315', 'Chih-Yi Chen', 7, NULL, 'Lecture', '1', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MUS-F 325', 'RHYTHM SECTION METHODS', '10511', 'Class Status', 'TuTh Tuesday, Thursday 9:10 AM–10:00 AM', 'JS 031', 'Sean Dobbins', 6, NULL, 'Lecture', '2', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'Survey of basic rhythm section techniques in jazz styles such as swing, shuffle, rock, funk, bossa nova, samba, Afro-Cuban, and ballads. The course will focus on developing basic skills on each of the rhythm section instruments (piano, guitar, bass, and drums) and understanding the role of each instrument.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 330', 'FOUNDATIONS IN LATIN AMERICAN AND CARIBBEAN PERCUSSION', '10964', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MA 401', 'Andy Miller', 0, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Hands-on percussion course focusing on folkloric percussion throughout Latin America and the Caribbean. These may include music traditions from Cuba, Puerto Rico, the Dominican Republic, Haiti, Trinidad and Tobago, Mexico, Guatemala, Belize, Venezuela, Colombia, Peru, and Brazil.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 337', 'WOODWIND TECHNIQUES', '2289', 'Closed', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 12:45 PM–1:35 PM', 'MA 454', 'Frank Diaz', 0, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Class instruction and teaching methods for flute, oboe, clarinet, saxophone, and bassoon.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 338', 'PERCUSSION TECHNIQUES', '2290', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–8:50 AM', 'MC 070', 'John Tafoya, Armon Brooks', 2, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Instruction in timpani, snare drum, xylophone bass drum, cymbals, Afro-Indo-Latin and jazz drums, etc. Laboratory class with emphasis on teaching techniques.', ARRAY[]::TEXT[], NULL),
